hierarchy.configuration_warnings:
PackedStringArray warnings = GeometryInstance3D::get_configuration_warnings();

bool mesh_found = false;
bool anim_material_found = false;

if (get_mesh().is_valid()) {
	mesh_found = true;
	for (int j = 0; j < get_mesh()->get_surface_count(); j++) {
		anim_material_found = Object::cast_to<ShaderMaterial>(get_mesh()->surface_get_material(j).ptr()) != nullptr;
		StandardMaterial3D *spat = Object::cast_to<StandardMaterial3D>(get_mesh()->surface_get_material(j).ptr());
		anim_material_found = anim_material_found || (spat && spat->get_billboard_mode() == StandardMaterial3D::BILLBOARD_PARTICLES);
	}
}

anim_material_found = anim_material_found || Object::cast_to<ShaderMaterial>(get_material_override().ptr()) != nullptr;
StandardMaterial3D *spat = Object::cast_to<StandardMaterial3D>(get_material_override().ptr());
anim_material_found = anim_material_found || (spat && spat->get_billboard_mode() == StandardMaterial3D::BILLBOARD_PARTICLES);

if (!mesh_found) {
	warnings.push_back(RTR("Nothing is visible because no mesh has been assigned."));
}

if (!anim_material_found && (get_param_max(PARAM_ANIM_SPEED) != 0.0 || get_param_max(PARAM_ANIM_OFFSET) != 0.0 || get_param_curve(PARAM_ANIM_SPEED).is_valid() || get_param_curve(PARAM_ANIM_OFFSET).is_valid())) {
	warnings.push_back(RTR("CPUParticles3D animation requires the usage of a StandardMaterial3D whose Billboard Mode is set to \"Particle Billboard\"."));
}

return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();
const CSGShape3D *current_shape = this;
while (current_shape) {
	if (!current_shape->brush || current_shape->brush->faces.is_empty()) {
		warnings.push_back(RTR("The CSGShape3D has an empty shape.\nCSGShape3D empty shapes typically occur because the mesh is not manifold.\nA manifold mesh forms a solid object without gaps, holes, or loose edges.\nEach edge must be a member of exactly two faces."));
		break;
	}
	current_shape = current_shape->parent_shape;
}
return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (clip_children_mode != CLIP_CHILDREN_DISABLED && is_inside_tree()) {
	bool warned_about_ancestor_clipping = false;
	bool warned_about_canvasgroup_ancestor = false;
	Node *n = get_parent();
	while (n) {
		CanvasItem *as_canvas_item = Object::cast_to<CanvasItem>(n);
		if (!warned_about_ancestor_clipping && as_canvas_item && as_canvas_item->clip_children_mode != CLIP_CHILDREN_DISABLED) {
			warnings.push_back(vformat(RTR("Ancestor \"%s\" clips its children, so this node will not be able to clip its children."), as_canvas_item->get_name()));
			warned_about_ancestor_clipping = true;
		}

		CanvasGroup *as_canvas_group = Object::cast_to<CanvasGroup>(n);
		if (!warned_about_canvasgroup_ancestor && as_canvas_group) {
			warnings.push_back(vformat(RTR("Ancestor \"%s\" is a CanvasGroup, so this node will not be able to clip its children."), as_canvas_group->get_name()));
			warned_about_canvasgroup_ancestor = true;
		}

		// Only break out early once both warnings have been triggered, so
		// that the user is aware of both possible reasons for clipping not working.
		if (warned_about_ancestor_clipping && warned_about_canvasgroup_ancestor) {
			break;
		}
		n = n->get_parent();
	}
}

return warnings;

children.configuration_warnings:
ERR_READ_THREAD_GUARD_V(PackedStringArray());
PackedStringArray warnings = CanvasItem::get_configuration_warnings();

if (data.mouse_filter == MOUSE_FILTER_IGNORE && !data.tooltip.is_empty()) {
	warnings.push_back(RTR("The Hint Tooltip won't be displayed as the control's Mouse Filter is set to \"Ignore\". To solve this, set the Mouse Filter to \"Stop\" or \"Pass\"."));
}

return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();

if (get_button_group().is_valid() && !is_toggle_mode()) {
	warnings.push_back(RTR("ButtonGroup is intended to be used only with buttons that have toggle_mode set to true."));
}

return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();

if (get_class() == "Container" && get_script().is_null()) {
	warnings.push_back(RTR("Container by itself serves no purpose unless a script configures its children placement behavior.\nIf you don't intend to add a script, use a plain Control node instead."));
}

return warnings;

PackedStringArray warnings = Container::get_configuration_warnings();

int found = 0;

for (int i = 0; i < get_child_count(); i++) {
	Control *c = as_sortable_control(get_child(i), SortableVisibilityMode::VISIBLE);
	if (!c || c == h_scroll || c == v_scroll || c == focus_panel || c == scroll_hint_top_left || c == scroll_hint_bottom_right) {
		continue;
	}

	found++;
}

if (found != 1) {
	warnings.push_back(RTR("ScrollContainer is intended to work with a single child control.\nUse a container as child (VBox, HBox, etc.), or a Control and set the custom minimum size manually."));
}

return warnings;

PackedStringArray warnings = Container::get_configuration_warnings();

bool has_viewport = false;
for (int i = 0; i < get_child_count(); i++) {
	if (Object::cast_to<SubViewport>(get_child(i))) {
		has_viewport = true;
		break;
	}
}
if (!has_viewport) {
	warnings.push_back(RTR("This node doesn't have a SubViewport as child, so it can't display its intended content.\nConsider adding a SubViewport as a child to provide something displayable."));
}

if (get_default_cursor_shape() != Control::CURSOR_ARROW) {
	warnings.push_back(RTR("The default mouse cursor shape of SubViewportContainer has no effect.\nConsider leaving it at its initial value `CURSOR_ARROW`."));
}

return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();

// FIXME: This is not ideal and the sizing model should be fixed,
// but for now we have to warn about this impossible to resolve combination.
// See GH-83546.
if (is_inside_tree() && get_tree()->get_edited_scene_root() != this) {
	// If the Label happens to be the root node of the edited scene, we don't need
	// to check what its parent is. It's going to be some node from the editor tree
	// and it can be a container, but that makes no difference to the user.
	Container *parent_container = Object::cast_to<Container>(get_parent_control());
	if (parent_container && autowrap_mode != TextServer::AUTOWRAP_OFF && get_custom_minimum_size() == Size2()) {
		warnings.push_back(RTR("Labels with autowrapping enabled must have a custom minimum size configured to work correctly inside a container."));
	}
}

// Ensure that the font can render all of the required glyphs.
Ref<Font> font;
if (settings.is_valid()) {
	font = settings->get_font();
}
if (font.is_null()) {
	font = theme_cache.font;
}

if (font.is_valid()) {
	_ensure_shaped();

	for (const Paragraph &para : paragraphs) {
		const Glyph *glyph = TS->shaped_text_get_glyphs(para.text_rid);
		int64_t glyph_count = TS->shaped_text_get_glyph_count(para.text_rid);
		for (int64_t i = 0; i < glyph_count; i++) {
			if (glyph[i].font_rid == RID() && glyph[i].index != 0) {
				warnings.push_back(RTR("The current font does not support rendering one or more characters used in this Label's text."));
				break;
			}
		}
	}
}

Ref<FontFile> ff = font;
if (ff.is_valid() && ff->is_multichannel_signed_distance_field()) {
	bool has_settings = settings.is_valid();
	int font_size = settings.is_valid() ? settings->get_font_size() : theme_cache.font_size;
	int outline_size = has_settings ? settings->get_outline_size() : theme_cache.font_outline_size;
	Vector<LabelSettings::StackedOutlineData> stacked_outline_datas = has_settings ? settings->get_stacked_outline_data() : Vector<LabelSettings::StackedOutlineData>();
	Vector<LabelSettings::StackedShadowData> stacked_shadow_datas = has_settings ? settings->get_stacked_shadow_data() : Vector<LabelSettings::StackedShadowData>();
	int max_outline_draw_size = outline_size;
	if (stacked_outline_datas.size() != 0) {
		int draw_iterations = stacked_outline_datas.size();
		for (int j = 0; j < draw_iterations; j++) {
			int stacked_outline_size = stacked_outline_datas[j].size;
			if (stacked_outline_size <= 0) {
				continue;
			}
			max_outline_draw_size += stacked_outline_size;
		}
	}
	if (stacked_shadow_datas.size() != 0) {
		int draw_iterations = stacked_shadow_datas.size();
		for (int j = 0; j < draw_iterations; j++) {
			LabelSettings::StackedShadowData stacked_shadow_data = stacked_shadow_datas[j];
			if (stacked_shadow_data.outline_size > 0) {
				max_outline_draw_size = MAX(max_outline_draw_size, stacked_shadow_data.outline_size);
			}
		}
	}
	float scale = (float)font_size / (float)ff->get_msdf_size();
	float ol = (float)max_outline_draw_size / scale / 4.0;
	float pxr = (float)ff->get_msdf_pixel_range() / 2.0 - 1.0;
	float r_pxr = (ol + 1.0) * 2.0;

	if (ol > pxr) {
		warnings.push_back(vformat(RTR("MSDF font pixel range is too small, some outlines/shadows will not render. Set MSDF pixel range to be at least %d to render all outlines/shadows."), Math::ceil(r_pxr)));
	}
}

return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();
if (secret_character.length() > 1) {
	warnings.push_back("Secret Character property supports only one character. Extra characters will be ignored.");
}
return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();

if (shared->exp_ratio && shared->min < 0) {
	warnings.push_back(RTR("If \"Exp Edit\" is enabled, \"Min Value\" must be greater or equal to 0."));
}

return warnings;

PackedStringArray warnings = Control::get_configuration_warnings();

if (stretch_mode == STRETCH_TILE) {
	Ref<AtlasTexture> at = texture;
	while (at.is_valid()) {
		if (at->get_margin() != Rect2()) {
			warnings.push_back(vformat(RTR("STRETCH_TILE mode is not supported for an AtlasTexture with non-zero margin.")));
			break;
		}
		at = at->get_atlas();
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();
if (frames.is_null()) {
	warnings.push_back(RTR("A SpriteFrames resource must be created or set in the \"Sprite Frames\" property in order for AnimatedSprite2D to display frames."));
}
return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();
if (!skeleton) {
	if (parent_bone) {
		warnings.push_back(RTR("This Bone2D chain should end at a Skeleton2D node."));
	} else {
		warnings.push_back(RTR("A Bone2D only works with a Skeleton2D or another Bone2D as parent node."));
	}
}

if (rest == Transform2D(0, 0, 0, 0, 0, 0)) {
	warnings.push_back(RTR("This bone lacks a proper REST pose. Go to the Skeleton2D node and set one."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (is_inside_tree()) {
	bool warned_about_ancestor_clipping = false;
	bool warned_about_canvasgroup_ancestor = false;
	Node *n = get_parent();
	while (n) {
		CanvasItem *as_canvas_item = Object::cast_to<CanvasItem>(n);
		if (!warned_about_ancestor_clipping && as_canvas_item && as_canvas_item->get_clip_children_mode() != CLIP_CHILDREN_DISABLED) {
			warnings.push_back(vformat(RTR("Ancestor \"%s\" clips its children, so this CanvasGroup will not function properly."), as_canvas_item->get_name()));
			warned_about_ancestor_clipping = true;
		}

		CanvasGroup *as_canvas_group = Object::cast_to<CanvasGroup>(n);
		if (!warned_about_canvasgroup_ancestor && as_canvas_group) {
			warnings.push_back(vformat(RTR("Ancestor \"%s\" is a CanvasGroup, so this CanvasGroup will not function properly."), as_canvas_group->get_name()));
			warned_about_canvasgroup_ancestor = true;
		}

		// Only break out early once both warnings have been triggered, so
		// that the user is aware of both possible reasons for clipping not working.
		if (warned_about_ancestor_clipping && warned_about_canvasgroup_ancestor) {
			break;
		}
		n = n->get_parent();
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (is_in_canvas && is_visible_in_tree()) {
	Vector<Node *> nodes = get_tree()->get_nodes_in_group("_canvas_modulate_" + itos(get_canvas().get_id()));

	if (nodes.size() > 1) {
		warnings.push_back(RTR("Only one visible CanvasModulate is allowed per canvas.\nWhen there are more than one, only one of them will be active. Which one is undefined."));
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (shapes.is_empty()) {
	warnings.push_back(RTR("This node has no shape, so it can't collide or interact with other objects.\nConsider adding a CollisionShape2D or CollisionPolygon2D as a child to define its shape."));
}

return warnings;

PackedStringArray warnings = CollisionObject2D::get_configuration_warnings();

if (SceneTree::is_fti_enabled_in_project() && !is_physics_interpolated()) {
	warnings.push_back(RTR("PhysicsBody2D will not work correctly on a non-interpolated branch of the SceneTree.\nCheck the node's inherited physics_interpolation_mode."));
}

return warnings;

Transform2D t = get_transform();

PackedStringArray warnings = PhysicsBody2D::get_configuration_warnings();

if (Math::abs(t.columns[0].length() - 1.0) > 0.05 || Math::abs(t.columns[1].length() - 1.0) > 0.05) {
	warnings.push_back(RTR("Size changes to RigidBody2D will be overridden by the physics engine when running.\nChange the size in children collision shapes instead."));
}

return warnings;

PackedStringArray warnings = RigidBody2D::get_configuration_warnings();

if (!parent_skeleton) {
	warnings.push_back(RTR("A PhysicalBone2D only works with a Skeleton2D or another PhysicalBone2D as a parent node!"));
}
if (parent_skeleton && bone2d_index <= -1) {
	warnings.push_back(RTR("A PhysicalBone2D needs to be assigned to a Bone2D node in order to function! Please set a Bone2D node in the inspector."));
}
if (!child_joint) {
	PhysicalBone2D *parent_bone = Object::cast_to<PhysicalBone2D>(get_parent());
	if (parent_bone) {
		warnings.push_back(RTR("A PhysicalBone2D node should have a Joint2D-based child node to keep bones connected! Please add a Joint2D-based node as a child to this node!"));
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (!Object::cast_to<CollisionObject2D>(get_parent())) {
	warnings.push_back(RTR("CollisionPolygon2D only serves to provide a collision shape to a CollisionObject2D derived node. Please only use it as a child of Area2D, StaticBody2D, RigidBody2D, CharacterBody2D, etc. to give them a shape."));
}

int polygon_count = polygon.size();
if (polygon_count == 0) {
	warnings.push_back(RTR("An empty CollisionPolygon2D has no effect on collision."));
} else {
	bool solids = build_mode == BUILD_SOLIDS;
	if (solids) {
		if (polygon_count < 3) {
			warnings.push_back(RTR("Invalid polygon. At least 3 points are needed in 'Solids' build mode."));
		}
	} else if (polygon_count < 2) {
		warnings.push_back(RTR("Invalid polygon. At least 2 points are needed in 'Segments' build mode."));
	}
}
if (one_way_collision && Object::cast_to<Area2D>(get_parent())) {
	warnings.push_back(RTR("The One Way Collision property will be ignored when the collision object is an Area2D."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

CollisionObject2D *col_object = Object::cast_to<CollisionObject2D>(get_parent());
if (col_object == nullptr) {
	warnings.push_back(RTR("CollisionShape2D only serves to provide a collision shape to a CollisionObject2D derived node.\nPlease only use it as a child of Area2D, StaticBody2D, RigidBody2D, CharacterBody2D, etc. to give them a shape."));
}
if (shape.is_null()) {
	warnings.push_back(RTR("A shape must be provided for CollisionShape2D to function. Please create a shape resource for it!"));
}
if (one_way_collision && Object::cast_to<Area2D>(col_object)) {
	warnings.push_back(RTR("The One Way Collision property will be ignored when the collision object is an Area2D."));
}

Ref<ConvexPolygonShape2D> convex = shape;
Ref<ConcavePolygonShape2D> concave = shape;
if (convex.is_valid() || concave.is_valid()) {
	warnings.push_back(RTR("The CollisionShape2D node has limited editing options for polygon-based shapes. Consider using a CollisionPolygon2D node instead."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

CanvasItemMaterial *mat = Object::cast_to<CanvasItemMaterial>(get_material().ptr());

if (get_material().is_null() || (mat && !mat->get_particles_animation())) {
	if (get_param_max(PARAM_ANIM_SPEED) != 0.0 || get_param_max(PARAM_ANIM_OFFSET) != 0.0 ||
			get_param_curve(PARAM_ANIM_SPEED).is_valid() || get_param_curve(PARAM_ANIM_OFFSET).is_valid()) {
		warnings.push_back(RTR("CPUParticles2D animation requires the usage of a CanvasItemMaterial with \"Particles Animation\" enabled."));
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (process_material.is_null()) {
	warnings.push_back(RTR("A material to process the particles is not assigned, so no behavior is imprinted."));
} else {
	CanvasItemMaterial *mat = Object::cast_to<CanvasItemMaterial>(get_material().ptr());

	if (get_material().is_null() || (mat && !mat->get_particles_animation())) {
		const ParticleProcessMaterial *process = Object::cast_to<ParticleProcessMaterial>(process_material.ptr());
		if (process &&
				(process->get_param_max(ParticleProcessMaterial::PARAM_ANIM_SPEED) != 0.0 || process->get_param_max(ParticleProcessMaterial::PARAM_ANIM_OFFSET) != 0.0 ||
						process->get_param_texture(ParticleProcessMaterial::PARAM_ANIM_SPEED).is_valid() || process->get_param_texture(ParticleProcessMaterial::PARAM_ANIM_OFFSET).is_valid())) {
			warnings.push_back(RTR("Particles2D animation requires the usage of a CanvasItemMaterial with \"Particles Animation\" enabled."));
		}
	}
}

if (trail_enabled && (OS::get_singleton()->get_current_rendering_method() == "gl_compatibility" || OS::get_singleton()->get_current_rendering_method() == "dummy")) {
	warnings.push_back(RTR("Particle trails are only available when using the Forward+ or Mobile renderer."));
}

if (sub_emitter != NodePath() && (OS::get_singleton()->get_current_rendering_method() == "gl_compatibility" || OS::get_singleton()->get_current_rendering_method() == "dummy")) {
	warnings.push_back(RTR("Particle sub-emitters are not available when using the Compatibility renderer."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (!warning.is_empty()) {
	warnings.push_back(warning);
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (occluder_polygon.is_null()) {
	warnings.push_back(RTR("An occluder polygon must be set (or drawn) for this occluder to take effect."));
}

if (occluder_polygon.is_valid() && occluder_polygon->get_polygon().is_empty()) {
	warnings.push_back(RTR("The occluder polygon for this occluder is empty. Please draw a polygon."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();
if (mesh.is_null()) {
	warnings.push_back(RTR("MeshInstance2D requires a Mesh to render anything. Please add a mesh resource for it!"));
}
return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (start_position.is_equal_approx(end_position)) {
	warnings.push_back(RTR("NavigationLink2D start position should be different than the end position to be useful."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

const Vector2 global_scale = get_global_scale();
if (global_scale.x < 0.001 || global_scale.y < 0.001) {
	warnings.push_back(RTR("NavigationObstacle2D does not support negative or zero scaling."));
}

if (radius > 0.0 && !get_global_transform().is_conformal()) {
	warnings.push_back(RTR("The agent radius can only be scaled uniformly. The largest value along the two axes of the global scale will be used to scale the radius. This value may change in unexpected ways when the node is rotated."));
}

if (radius > 0.0 && get_global_skew() != 0.0) {
	warnings.push_back(RTR("Skew has no effect on the agent radius."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (is_visible_in_tree() && is_inside_tree()) {
	if (navigation_polygon.is_null()) {
		warnings.push_back(RTR("A NavigationPolygon resource must be set or created for this node to work. Please set a property or draw a polygon."));
	}
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (!Object::cast_to<ParallaxBackground>(get_parent())) {
	warnings.push_back(RTR("ParallaxLayer node only works when set as child of a ParallaxBackground node."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (!has_node(remote_node) || !Object::cast_to<Node2D>(get_node(remote_node))) {
	warnings.push_back(RTR("Path property must point to a valid Node2D node to work."));
}

return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

if (shape.is_null()) {
	warnings.push_back(RTR("This node cannot interact with other objects unless a Shape2D is assigned."));
}
return warnings;

PackedStringArray warnings = Node2D::get_configuration_warnings();

warnings.push_back(RTR("The TileMap node is deprecated as it is superseded by the use of multiple TileMapLayer nodes.\nTo convert a TileMap to a set of TileMapLayer nodes, open the TileMap bottom panel with this node selected, click the toolbox icon in the top-right corner and choose \"Extract TileMap layers as individual TileMapLayer nodes\"."));

// Retrieve the set of Z index values with a Y-sorted layer.
RBSet<int> y_sorted_z_index;
for (const TileMapLayer *layer : layers) {
	if (layer->is_y_sort_enabled()) {
		y_sorted_z_index.insert(layer->get_z_index());
	}
}

// Check if we have a non-sorted layer in a Z-index with a Y-sorted layer.
for (const TileMapLayer *layer : layers) {
	if (!layer->is_y_sort_enabled() && y_sorted_z_index.has(layer->get_z_index())) {
		warnings.push_back(RTR("A Y-sorted layer has the same Z-index value as a not Y-sorted layer.\nThis may lead to unwanted behaviors, as a layer that is not Y-sorted will be Y-sorted as a whole with tiles from Y-sorted layers."));
		break;
	}
}

if (!is_y_sort_enabled()) {
	// Check if Y-sort is enabled on a layer but not on the node.
	for (const TileMapLayer *layer : layers) {
		if (layer->is_y_sort_enabled()) {
			warnings.push_back(RTR("A TileMap layer is set as Y-sorted, but Y-sort is not enabled on the TileMap node itself."));
			break;
		}
	}
} else {
	// Check if Y-sort is enabled on the node, but not on any of the layers.
	bool need_warning = true;
	for (const TileMapLayer *layer : layers) {
		if (layer->is_y_sort_enabled()) {
			need_warning = false;
			break;
		}
	}
	if (need_warning) {
		warnings.push_back(RTR("The TileMap node is set as Y-sorted, but Y-sort is not enabled on any of the TileMap's layers.\nThis may lead to unwanted behaviors, as a layer that is not Y-sorted will be Y-sorted as a whole."));
	}
}

// Check if we are in isometric mode without Y-sort enabled.
if (tile_set.is_valid() && tile_set->get_tile_shape() == TileSet::TILE_SHAPE_ISOMETRIC) {
	bool warn = !is_y_sort_enabled();
	if (!warn) {
		for (const TileMapLayer *layer : layers) {
			if (!layer->is_y_sort_enabled()) {
				warn = true;
				break;
			}
		}
	}

	if (warn) {
		warnings.push_back(RTR("Isometric TileSet will likely not look as intended without Y-sort enabled for the TileMap and all of its layers."));
	}
}

return warnings;

hierarchy.configuration_warnings:
PackedStringArray warnings = GeometryInstance3D::get_configuration_warnings();

bool meshes_found = false;
bool anim_material_found = false;

for (int i = 0; i < draw_passes.size(); i++) {
	if (draw_passes[i].is_valid()) {
		meshes_found = true;
		for (int j = 0; j < draw_passes[i]->get_surface_count(); j++) {
			anim_material_found = Object::cast_to<ShaderMaterial>(draw_passes[i]->surface_get_material(j).ptr()) != nullptr;
			BaseMaterial3D *spat = Object::cast_to<BaseMaterial3D>(draw_passes[i]->surface_get_material(j).ptr());
			anim_material_found = anim_material_found || (spat && spat->get_billboard_mode() == StandardMaterial3D::BILLBOARD_PARTICLES);
		}
		if (anim_material_found) {
			break;
		}
	}
}

anim_material_found = anim_material_found || Object::cast_to<ShaderMaterial>(get_material_override().ptr()) != nullptr;
	BaseMaterial3D *spat = Object::cast_to<BaseMaterial3D>(get_material_override().ptr());
	anim_material_found = anim_material_found || (spat && spat->get_billboard_mode() == BaseMaterial3D::BILLBOARD_PARTICLES);
}

if (!meshes_found) {
	warnings.push_back(RTR("Nothing is visible because meshes have not been assigned to draw passes."));
}

if (process_material.is_null()) {
	warnings.push_back(RTR("A material to process the particles is not assigned, so no behavior is imprinted."));
} else {
	const ParticleProcessMaterial *process = Object::cast_to<ParticleProcessMaterial>(process_material.ptr());
	if (!anim_material_found && process &&
			(process->get_param_max(ParticleProcessMaterial::PARAM_ANIM_SPEED) != 0.0 || process->get_param_max(ParticleProcessMaterial::PARAM_ANIM_OFFSET) != 0.0 ||
					process->get_param_texture(ParticleProcessMaterial::PARAM_ANIM_SPEED).is_valid() || process->get_param_texture(ParticleProcessMaterial::PARAM_ANIM_OFFSET).is_valid())) {
		warnings.push_back(RTR("Particles animation requires the usage of a BaseMaterial3D whose Billboard Mode is set to \"Particle Billboard\"."));
	}
}

if (trail_enabled) {
	int dp_count = 0;
	bool missing_trails = false;
	bool no_materials = false;

	for (int i = 0; i < draw_passes.size(); i++) {
		Ref<Mesh> draw_pass = draw_passes[i];
		if (draw_pass.is_valid() && draw_pass->get_builtin_bind_pose_count() > 0) {
			dp_count++;
		}

		if (draw_pass.is_valid()) {
			int mats_found = 0;
			for (int j = 0; j < draw_passes[i]->get_surface_count(); j++) {
				BaseMaterial3D *spat = Object::cast_to<BaseMaterial3D>(draw_passes[i]->surface_get_material(j).ptr());
				if (spat) {
					mats_found++;
				}
				if (spat && !spat->get_flag(BaseMaterial3D::FLAG_PARTICLE_TRAILS_MODE)) {
					missing_trails = true;
				}
			}

			if (mats_found != draw_passes[i]->get_surface_count()) {
				no_materials = true;
			}
		}
	}

	BaseMaterial3D *spat = Object::cast_to<BaseMaterial3D>(get_material_override().ptr());
	if (spat) {
		no_materials = false;
	}
	if (spat && !spat->get_flag(BaseMaterial3D::FLAG_PARTICLE_TRAILS_MODE)) {
		missing_trails = true;
	}

	if (dp_count && skin.is_valid()) {
		warnings.push_back(RTR("Using Trail meshes with a skin causes Skin to override Trail poses. Suggest removing the Skin."));
	} else if (dp_count == 0 && skin.is_null()) {
		warnings.push_back(RTR("Trails active, but neither Trail meshes or a Skin were found."));
	} else if (dp_count > 1) {
		warnings.push_back(RTR("Only one Trail mesh is supported. If you want to use more than a single mesh, a Skin is needed (see documentation)."));
	}

	if ((dp_count || skin.is_valid()) && (missing_trails || no_materials)) {
		warnings.push_back(RTR("Trails enabled, but one or more mesh materials are either missing or not set for trails rendering."));
	}
	if (OS::get_singleton()->get_current_rendering_method() == "gl_compatibility" || OS::get_singleton()->get_current_rendering_method() == "dummy") {
		warnings.push_back(RTR("Particle trails are only available when using the Forward+ or Mobile renderer."));
	}
}

if (sub_emitter != NodePath() && (OS::get_singleton()->get_current_rendering_method() == "gl_compatibility" || OS::get_singleton()->get_current_rendering_method() == "dummy")) {
	warnings.push_back(RTR("Particle sub-emitters are only available when using the Forward+ or Mobile renderer."));
}

return warnings;

PackedStringArray warnings = GeometryInstance3D::get_configuration_warnings();
if (mesh.is_null()) {
	warnings.push_back(RTR("MeshInstance3D requires a Mesh to render anything. Please add a mesh resource for it!"));
}
return warnings;

// The mere existence of this node is warning.
PackedStringArray warnings = Node::get_configuration_warnings();
if (!original_scene.is_empty()) {
	warnings.push_back(vformat(RTR("This node was an instance of scene '%s', which was no longer available when this scene was loaded."), original_scene));
	warnings.push_back(vformat(RTR("Saving current scene will discard instance and all its properties, including editable children edits (if existing).")));
} else if (!original_class.is_empty()) {
	warnings.push_back(vformat(RTR("This node was saved as class type '%s', which was no longer available when this scene was loaded."), original_class));
	warnings.push_back(RTR("Data from the original node is kept as a placeholder until this type of node is available again. It can hence be safely re-saved without risk of data loss."));
} else {
	warnings.push_back(RTR("Unrecognized missing node. Check scene dependency errors for details."));
}
return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (root_path.is_empty() || !has_node(root_path)) {
	warnings.push_back(RTR("A valid NodePath must be set in the \"Root Path\" property in order for MultiplayerSynchronizer to be able to synchronize properties."));
}

return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (!Object::cast_to<Node2D>(get_parent())) {
	warnings.push_back(RTR("The NavigationAgent2D can be used only under a Node2D inheriting parent node."));
}

return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (!Object::cast_to<Node3D>(get_parent())) {
	warnings.push_back(RTR("The NavigationAgent3D can be used only under a Node3D inheriting parent node."));
}

