PackedStringArray warnings = VisualInstance3D::get_configuration_warnings();

if (OS::get_singleton()->get_current_rendering_method() == "gl_compatibility") {
	warnings.push_back(RTR("VoxelGI nodes are not supported when using the Compatibility renderer yet. Support will be added in a future release."));
} else if (OS::get_singleton()->get_current_rendering_method() == "dummy") {
	warnings.push_back(RTR("VoxelGI nodes are not supported when using the Dummy renderer."));
} else if (probe_data.is_null()) {
	warnings.push_back(RTR("No VoxelGI data set, so this node is disabled. Bake static objects to enable GI."));
}
return warnings;

PackedStringArray warnings = Node3D::get_configuration_warnings();

if (is_visible() && is_inside_tree()) {
	// Warn if the node has a parent which isn't an XROrigin3D!
	Node *parent = get_parent();
	XROrigin3D *origin = Object::cast_to<XROrigin3D>(parent);
	if (parent && origin == nullptr) {
		warnings.push_back(RTR("XRNode3D may not function as expected without an XROrigin3D node as its parent."));
	};

	if (tracker_name == "") {
		warnings.push_back(RTR("No tracker name is set."));
	}

	if (pose_name == "") {
		warnings.push_back(RTR("No pose is set."));
	}

	if (SceneTree::is_fti_enabled_in_project() && is_physics_interpolated()) {
		warnings.push_back(RTR("XRNode3D should have physics_interpolation_mode set to OFF in order to avoid jitter."));
	}
}

return warnings;

hierarchy.configuration_warnings:
PackedStringArray warnings = Popup::get_configuration_warnings();

if (!DisplayServer::get_singleton()->is_window_transparency_available() && !GLOBAL_GET_CACHED(bool, "display/window/subwindows/embed_subwindows")) {
