	if (sb.is_valid() && (sb->get_shadow_size() > 0 || sb->get_corner_radius(CORNER_TOP_LEFT) > 0 || sb->get_corner_radius(CORNER_TOP_RIGHT) > 0 || sb->get_corner_radius(CORNER_BOTTOM_LEFT) > 0 || sb->get_corner_radius(CORNER_BOTTOM_RIGHT) > 0)) {
		warnings.push_back(RTR("The current theme style has shadows and/or rounded corners for popups, but those won't display correctly if \"display/window/per_pixel_transparency/allowed\" isn't enabled in the Project Settings, nor if it isn't supported."));
	}
}

return warnings;

PackedStringArray warnings = Popup::get_configuration_warnings();

if (!DisplayServer::get_singleton()->is_window_transparency_available() && !GLOBAL_GET_CACHED(bool, "display/window/subwindows/embed_subwindows")) {
	Ref<StyleBoxFlat> sb = theme_cache.panel_style;
	if (sb.is_valid() && (sb->get_shadow_size() > 0 || sb->get_corner_radius(CORNER_TOP_LEFT) > 0 || sb->get_corner_radius(CORNER_TOP_RIGHT) > 0 || sb->get_corner_radius(CORNER_BOTTOM_LEFT) > 0 || sb->get_corner_radius(CORNER_BOTTOM_RIGHT) > 0)) {
		warnings.push_back(RTR("The current theme style has shadows and/or rounded corners for popups, but those won't display correctly if \"display/window/per_pixel_transparency/allowed\" isn't enabled in the Project Settings, nor if it isn't supported."));
	}
}

return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (!active) {
	warnings.push_back(RTR("ShaderGlobalsOverride is not active because another node of the same type is in the scene."));
}

return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (wait_time < 0.05 - CMP_EPSILON) {
	warnings.push_back(RTR("Very low timer wait times (< 0.05 seconds) may behave in significantly different ways depending on the rendered or physics frame rate.\nConsider using a script's process loop instead of relying on a Timer for very low wait times."));
}

return warnings;

ERR_MAIN_THREAD_GUARD_V(PackedStringArray());
PackedStringArray warnings = Node::get_configuration_warnings();

if (size.x <= 1 || size.y <= 1) {
	warnings.push_back(RTR("The Viewport size must be greater than or equal to 2 pixels on both dimensions to render anything."));
}
return warnings;

PackedStringArray warnings = Node::get_configuration_warnings();

if (environment.is_null() && camera_attributes.is_null()) {
	warnings.push_back(RTR("To have any visible effect, WorldEnvironment requires its \"Environment\" property to contain an Environment, its \"Camera Attributes\" property to contain a CameraAttributes resource, or both."));
}

if (!is_inside_tree()) {
	return warnings;
}

if (environment.is_valid() && get_viewport()->find_world_3d()->get_environment() != environment) {
	warnings.push_back(("Only the first Environment has an effect in a scene (or set of instantiated scenes)."));
}

if (camera_attributes.is_valid() && get_viewport()->find_world_3d()->get_camera_attributes() != camera_attributes) {
	warnings.push_back(RTR("Only one WorldEnvironment is allowed per scene (or set of instantiated scenes)."));
}

if (compositor.is_valid() && get_viewport()->find_world_3d()->get_compositor() != compositor) {
	warnings.push_back(("Only the first Compositor has an effect in a scene (or set of instantiated scenes)."));
}

return warnings;
